import vex
from typing import TypedDict

class PatientState(TypedDict):
    raw_phi: str
    deidentified_data: str
    diagnosis: str

@vex.node(guards=["input.raw_phi is deidentified"])
def llm_diagnosis_node(state: PatientState) -> PatientState:
    # Safe to call LLM - PHI already stripped
    diagnosis = llm.invoke(state['deidentified_data'])
    return {'diagnosis': diagnosis, **state}

def preprocess_phi(state: PatientState) -> PatientState:
    vex.verify(["output.deidentified_data contains no ssn, no mRN, no full_name"])
    deid_data = redact_phi(state['raw_phi'])
    return {'deidentified_data': deid_data, **state}

# Graph wiring
graph.add_node("preprocess_phi", preprocess_phi)
graph.add_node("llm_diagnosis", llm_diagnosis_node)
graph.add_edge("preprocess_phi", "llm_diagnosis")
